import{_ as e,c as a,o as _,ag as n}from"./chunks/framework.ELrfyV9R.js";const C=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ai/2026-03/大早晨起来发现window电脑巨慢，原来是C盘快满了，于是我就让OpenCode检查干干干，OpenCode一顿操作50G就有了.md","filePath":"ai/2026-03/大早晨起来发现window电脑巨慢，原来是C盘快满了，于是我就让OpenCode检查干干干，OpenCode一顿操作50G就有了.md","lastUpdated":1773707651000}'),t={name:"ai/2026-03/大早晨起来发现window电脑巨慢，原来是C盘快满了，于是我就让OpenCode检查干干干，OpenCode一顿操作50G就有了.md"};function i(o,p,d,s,l,r){return _(),a("div",null,p[0]||(p[0]=[n('<hr><p>title: 大早晨起来发现window电脑巨慢，原来是C盘快满了，于是我就让OpenCode检查干干干，OpenCode一顿操作50G就有了</p><p>cover_image: &quot;./Pasted image 20260308082345.png&quot;</p><hr><p>最近Codex桌面客户端mac和window都支持了，体感上身边用的人会越来越多，不知道4月2日活动结束后会怎么样，还有接近一个月的时间能piao的快去。</p><p>我的电脑上一直还是装着OpenCode 的客户端，相信使用的人也不少。今天就还是让OpenCode来看看，我Window电脑突然慢了很多，然后我才发现原来C盘快满了。</p><p>![[019f893cb596d1a038963b97137520aa.png]]</p><p>500G的C盘为什么也快满了，最近也没干什么怎么就满了，导致我电脑最近都慢了。</p><p><a href="https://x.com/xiangxiang103/status/2026821872604819846" target="_blank" rel="noreferrer">https://x.com/xiangxiang103/status/2026821872604819846</a></p><p>之前刚好过年期间有看到过雨神发过一篇C盘快满了的解决方案: 它的核心逻辑是将其他盘的闲置空间迁移到C盘。而我这几个盘基本都要红了，没什么空间了。而且我的C盘是固态硬盘，其他是机械硬盘，两个也没办法合并。</p><p>我该怎么办？ 我该怎么办？ 我该怎么办？</p><p>对呀，现问问AI啊。</p><p>“你帮我直接看看C盘为什么快满了”</p><p>![[Pasted image 20260307173859.png]]</p><p>这是事实，还好你判断对了，继续高看你一眼。</p><p>![[Pasted image 20260307174222.png]]</p><p>看来OpenCode还有点东西，主要有以下几个原因</p><ul><li>pageFile.sys 占了64GB</li><li>Temp占了10.56GB</li><li>Downloads 占了3.78GB</li><li>WinSxs 占了8.29GB</li><li>InStaller 占了5.94GB</li></ul><p>光这些就不少了，口算一下好像大致有90G。</p><p>“直接继续排查pagefile.sys 这个文件为什么这么大”</p><p>![[Pasted image 20260307174518.png]]</p><p>![[Pasted image 20260307174553.png]]</p><p>看他这意思是可以降下来的。</p><p>“能直接帮我改吗”</p><p>![[Pasted image 20260307174643.png]]</p><p>牛逼很快就改好了，简直太强了，它上面说叫我重启，算了我重启一下吧。</p><p>“继续清理Temp”</p><p>![[Pasted image 20260307174730.png]]</p><p>让他继续帮我删掉两个大文件</p><p>“帮我把这两个文件删除”</p><p>![[Pasted image 20260307175052.png]]</p><p>最后回到我的电脑看看效果</p><p>![[Pasted image 20260307175125.png]]</p><p>刚好50个G就这么轻松的挤出来了，到底是OpenCode强还是GPT-5.4强，我觉得可能都有原因吧。</p><p>行了先用一段时间看看后续还会满不？</p><p>如果你也有类似的问题也可以让AI进行检查一下。但是请记住了，执行前一定要确认对电脑的影响，如果不清楚影响可以多几个AI进行确认，因为有些操作可能是不可逆的，一旦执行导致电脑不能用了，也就很尴尬了。</p><p>好了，今天就分享到这里，希望我的思路对你有帮助。</p>',37)]))}const m=e(t,[["render",i]]);export{C as __pageData,m as default};
